import cv2
import face_recognition
import numpy as np
import os
from flask import Flask, request, jsonify

# Load employee photos
employee_photos = []
employee_names = []

for filename in os.listdir('employee_photos'):
    image = cv2.imread(os.path.join('employee_photos', filename))
    employee_photos.append(image)
    employee_names.append(filename.split('.')[0])

# Encode employee faces
employee_encodings = [face_recognition.face_encodings(photo)[0] for photo in employee_photos]

# Create Flask app
app = Flask(__name__)

@app.route('/recognize_face', methods=['POST'])
def recognize_face():
    # Get image from request
    image = request.files['image'].read()
    image = cv2.imdecode(np.frombuffer(image, np.uint8), cv2.IMREAD_COLOR)

    # Encode image
    image_encoding = face_recognition.face_encodings(image)[0]

    # Find matches
    distances = face_recognition.face_distance(employee_encodings, image_encoding)
    matches = [name for name, distance in zip(employee_names, distances) if distance < 0.6]

    # Return confidence scores
    confidence_scores = [1 - distance for distance in distances]
    probability_distribution = {name: score for name, score in zip(employee_names, confidence_scores)}

    return jsonify(probability_distribution)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)